selector_to_html = {"a[href=\"../../example/Cpp.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2 </span>C++\u63a5\u53e3\u4f7f\u7528\u793a\u4f8b<a class=\"headerlink\" href=\"#c\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>\u672c\u7ae0\u8282\u5c06\u5e26\u60a8\u5b9e\u73b0\u7d22\u5f15\u6240\u793a\u82e5\u5e72\u529f\u80fd</strong></p><p><strong>\u6784\u5efa &amp; \u8fd0\u884c\u8bf4\u660e</strong></p>", "a[href=\"#id2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u6838\u5fc3\u529f\u80fd<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2><h3>\u89c6\u89c9\u4f20\u611f\u5668<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#imu\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">IMU\u8bdd\u9898<a class=\"headerlink\" href=\"#imu\" title=\"Link to this heading\">\uf0c1</a></h2><p>\u5305\u62ec\u72ec\u7acb\u7684\u80f8\u90e8IMU\u548c\u80ef\u90e8IMU, \u5747\u4f4d\u4e8e\u5f00\u53d1\u8ba1\u7b97\u5355\u5143(PC2) <br/>\n\u4e5f\u53ef\u4f7f\u7528 <a class=\"reference internal\" href=\"#interface-lidar\">Lidar</a> \u548c <a class=\"reference internal\" href=\"#interface-rgbd-camera\">\u6df1\u5ea6\u76f8\u673a</a> \u9644\u5e26\u7684IMU</p>", "a[href=\"#id1\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.4.1 </span>\u4f20\u611f\u5668\u63a5\u53e3<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>\u4f20\u611f\u5668\u63a5\u53e3\u63d0\u4f9b\u4e86\u673a\u5668\u4eba\u5404\u79cd\u4f20\u611f\u5668\u7684\u6570\u636e\u83b7\u53d6\u548c\u63a7\u5236\u80fd\u529b\uff0c\u5305\u62ec\u76f8\u673a\u3001IMU\u3001\u6fc0\u5149\u96f7\u8fbe\u3001\u89e6\u6478\u4f20\u611f\u5668\u7b49\u3002</strong></p>", "a[href=\"#id4\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u59ff\u6001\u4f20\u611f\u5668<a class=\"headerlink\" href=\"#id4\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#interface-lidar\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Lidar\u8bdd\u9898<a class=\"headerlink\" href=\"#interface-lidar\" title=\"Link to this heading\">\uf0c1</a></h2><p>\u63d0\u4f9bLidar\u70b9\u4e91\u6570\u636e\u548cLidar\u5185\u7f6eIMU\u6570\u636e, \u53ef\u7528\u4e8e\u907f\u969c\u3001\u5efa\u56fe\u5b9a\u4f4d\u7b49 <br/>\nLidar\u4f4d\u4e8e\u5f00\u53d1\u8ba1\u7b97\u5355\u5143(PC2),\n\u6570\u636e\u5e26\u5bbd10MB/s\u91cf\u7ea7, <strong>\u4e0d\u5efa\u8bae</strong>\u8de8\u8ba1\u7b97\u5355\u5143\u8ba2\u9605</p>", "a[href=\"#id7\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u5934\u90e8\u89e6\u6478\u72b6\u6001\u8bdd\u9898<a class=\"headerlink\" href=\"#id7\" title=\"Link to this heading\">\uf0c1</a></h2><p>\u652f\u6301\u529f\u80fd:</p>", "a[href=\"../../example/Cpp.html#cpp-echo-camera-head-rear\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u5934\u90e8\u540e\u7f6e\u5355\u76ee\u76f8\u673a\u6570\u636e\u8ba2\u9605<a class=\"headerlink\" href=\"#cpp-echo-camera-head-rear\" title=\"Link to this heading\">\uf0c1</a></h3><p><strong>\u8be5\u793a\u4f8b\u4e2d\u7528\u5230\u4e86echo_camera_head_rear</strong>\uff0c\u901a\u8fc7\u8ba2\u9605<code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/rgb_head_rear/</span></code>\u8bdd\u9898\u6765\u63a5\u6536\u673a\u5668\u4eba\u7684\u5934\u90e8\u540e\u7f6e\u5355\u76ee\u76f8\u673a\u6570\u636e\uff0c\u652f\u6301RGB\u56fe(\u53ca\u5176mask\u5904\u7406)\u3001\u538b\u7f29\u56fe\u548c\u76f8\u673a\u5185\u53c2\u6570\u636e\u3002</p><p><strong>\u529f\u80fd\u7279\u70b9\uff1a</strong></p>", "a[href=\"#id11\"]": "<figure class=\"align-center\" id=\"id11\">\n<a class=\"reference internal image-reference\" href=\"../../_images/camera_head_rear_obstructed.jpg\"><img alt=\"\u540e\u89c6RGB\u76f8\u673a\u906e\u6321\u793a\u610f\u56fe\" src=\"../../_images/camera_head_rear_obstructed.jpg\" style=\"width: 100%;\"/>\n</a>\n<figcaption>\n<p><span class=\"caption-text\">\u540e\u89c6RGB\u76f8\u673a\u906e\u6321\u793a\u610f\u56fe</span><a class=\"headerlink\" href=\"#id11\" title=\"Link to this image\">\uf0c1</a></p>\n</figcaption>\n</figure>", "a[href=\"../../example/Python.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1 </span>Python\u63a5\u53e3\u4f7f\u7528\u793a\u4f8b<a class=\"headerlink\" href=\"#python\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>\u672c\u7ae0\u8282\u5c06\u5e26\u60a8\u5b9e\u73b0\u7d22\u5f15\u6240\u793a\u82e5\u5e72\u529f\u80fd</strong></p><p><strong>\u6784\u5efa &amp; \u8fd0\u884c\u8bf4\u660e</strong></p>", "a[href=\"#interface-rgbd-camera\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u6df1\u5ea6\u76f8\u673a\u8bdd\u9898<a class=\"headerlink\" href=\"#interface-rgbd-camera\" title=\"Link to this heading\">\uf0c1</a></h2><p>\u6df1\u5ea6\u76f8\u673a\u4f4d\u4e8e\u5f00\u53d1\u8ba1\u7b97\u5355\u5143(PC2), \u53ef\u7528\u4e8e\u76ee\u6807\u68c0\u6d4b\u3001\u7a7a\u95f4\u907f\u969c\u3001\u73af\u5883\u8bed\u4e49\u83b7\u53d6\u7b49 <br/>\n<strong>\u539f\u59cb\u56fe\u50cf\u6570\u636e\u6bcf\u8def\u5e26\u5bbd\u7ea625MB/s, \u4ec5\u9650\u8bbe\u5907\u6240\u5728\u8ba1\u7b97\u5355\u5143\u4e0a\u4f7f\u7528, \u5207\u52ff\u8de8\u8ba1\u7b97\u5355\u5143\u8ba2\u9605</strong></p>", "a[href=\"#id8\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u53cc\u76ee\u76f8\u673a\u8bdd\u9898<a class=\"headerlink\" href=\"#id8\" title=\"Link to this heading\">\uf0c1</a></h2><p>\u53cc\u76ee\u76f8\u673a\u4f4d\u4e8e\u5f00\u53d1\u8ba1\u7b97\u5355\u5143(PC2), \u53ef\u7528\u4e8e\u7acb\u4f53\u89c6\u89c9\u3001\u9065\u64cd\u3001\u611f\u77e5\u907f\u969c\u3001\u76ee\u6807\u8bc6\u522b\u3001VIO SLAM\u3001VLA\u7b49 <br/>\n\u539f\u59cb\u56fe\u50cf\u6bcf\u8def\u6570\u636e\u5e26\u5bbd90MB/s, <strong>\u4ec5\u9650\u8bbe\u5907\u6240\u5728\u8ba1\u7b97\u5355\u5143\u4e0a\u4f7f\u7528, \u5207\u52ff\u8de8\u8ba1\u7b97\u5355\u5143\u8ba2\u9605</strong></p>", "a[href=\"#id10\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u5b89\u5168\u6ce8\u610f\u4e8b\u9879<a class=\"headerlink\" href=\"#id10\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#id5\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u73af\u5883\u611f\u77e5\u4f20\u611f\u5668<a class=\"headerlink\" href=\"#id5\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#id9\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u7f16\u7a0b\u793a\u4f8b<a class=\"headerlink\" href=\"#id9\" title=\"Link to this heading\">\uf0c1</a></h2><p>\u8be6\u7ec6\u7684\u7f16\u7a0b\u793a\u4f8b\u548c\u4ee3\u7801\u8bf4\u660e\u8bf7\u53c2\u8003\uff1a</p>", "a[href=\"#id3\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u89c6\u89c9\u4f20\u611f\u5668<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#rgb\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u540e\u89c6RGB\u76f8\u673a\u8bdd\u9898<a class=\"headerlink\" href=\"#rgb\" title=\"Link to this heading\">\uf0c1</a></h2><p>\u540e\u89c6RGB\u76f8\u673a\u4f4d\u4e8e\u5f00\u53d1\u8ba1\u7b97\u5355\u5143(PC2), \u53ef\u7528\u4e8e\u89c6\u89c9\u8f85\u52a9\u5b9a\u4f4d\u3001\u573a\u666f\u8bed\u4e49\u611f\u77e5\u7b49 <br/>\n\u539f\u59cb\u56fe\u50cf\u6570\u636e\u5e26\u5bbd90MB/s, <strong>\u4ec5\u9650\u8bbe\u5907\u6240\u5728\u8ba1\u7b97\u5355\u5143\u4e0a\u4f7f\u7528, \u5207\u52ff\u8de8\u8ba1\u7b97\u5355\u5143\u8ba2\u9605</strong></p>", "a[href=\"#id6\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u6807\u51c6\u4f20\u611f\u5668\u6d88\u606f<a class=\"headerlink\" href=\"#id6\" title=\"Link to this heading\">\uf0c1</a></h2><p>\u4f20\u611f\u5668\u63a5\u53e3\u5927\u591a\u4f7f\u7528ROS\u6807\u51c6\u4f20\u611f\u5668\u5b9a\u4e49<code class=\"docutils literal notranslate\"><span class=\"pre\">sensor_msgs</span></code>\u4e2d\u7684\u6d88\u606f\u7c7b\u578b:</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false, theme: 'material', duration: [300, 200], delay: [200, 100],

            });
        };
    };
    console.log("tippy tips loaded!");
};
